import { AbsoluteFill, Img, Audio, useCurrentFrame, useVideoConfig, interpolate, spring } from "remotion";

export default function TikTokTutorial({ inputs }) {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  const images = [inputs["input-1"], inputs["input-2"], inputs["input-3"], inputs["input-4"]].filter(Boolean);
  const audio = inputs["audio-in"];

  const scenes = [
    { start: 0,   end: 150, caption: 'Stop scrolling.', sub: 'What if AI made your videos?' },
    { start: 150, end: 300, caption: 'Editing takes forever.', sub: 'Hours of work for minutes of content.' },
    { start: 300, end: 480, caption: 'Just connect the nodes.', sub: 'Type what you want. Hit generate.' },
    { start: 480, end: 630, caption: 'This is Image Flow.', sub: 'AI video creation in seconds.' },
    { start: 630, end: 750, caption: 'Try it free today.', sub: 'imageflow.ai' },
  ];

  const sp = (delay, damping = 12, stiffness = 80) =>
    spring({ frame: Math.max(0, frame - delay), fps, config: { damping, stiffness } });

  const sceneIdx = scenes.findIndex(s => frame >= s.start && frame < s.end);
  const scene = scenes[Math.max(0, sceneIdx === -1 ? scenes.length - 1 : sceneIdx)];
  const sceneProgress = (frame - scene.start) / (scene.end - scene.start);

  const imgIdx = sceneIdx >= 0 && sceneIdx < images.length ? sceneIdx : sceneIdx >= images.length ? images.length - 1 : 0;
  const currentImg = images[imgIdx] || images[0];
  const nextImgIdx = Math.min(imgIdx + 1, images.length - 1);
  const nextImg = images[nextImgIdx];

  const zoom = interpolate(sceneProgress, [0, 1], [1, 1.1]);

  const transFrames = 12;
  const isTransitioning = scene && (frame > scene.end - transFrames) && sceneIdx < scenes.length - 1;
  const transProg = isTransitioning
    ? interpolate(frame, [scene.end - transFrames, scene.end], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
    : 0;

  const captionDelay = scene ? scene.start + 5 : 0;
  const captionIn = sp(captionDelay, 14, 100);
  const subIn = sp(scene ? scene.start + 18 : 0, 14, 80);

  const isCTA = sceneIdx === scenes.length - 1 || sceneIdx === -1;
  const ctaPulse = isCTA ? 0.92 + Math.sin(frame * 0.2) * 0.08 : 1;

  return (
    <AbsoluteFill style={{ background: '#000' }}>
      {currentImg && (
        <Img src={currentImg} style={{
          position: 'absolute', width: '100%', height: '100%', objectFit: 'cover',
          transform: `scale(${zoom})`,
          opacity: 1 - transProg,
        }} />
      )}
      {isTransitioning && nextImg && (
        <Img src={nextImg} style={{
          position: 'absolute', width: '100%', height: '100%', objectFit: 'cover',
          opacity: transProg,
        }} />
      )}

      <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(ellipse at center, transparent 40%, rgba(0,0,0,0.7) 100%)' }} />
      <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: '60%', background: 'linear-gradient(to top, rgba(0,0,0,0.9) 0%, rgba(0,0,0,0.5) 40%, transparent 100%)' }} />
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '20%', background: 'linear-gradient(to bottom, rgba(0,0,0,0.5) 0%, transparent 100%)' }} />

      {scene && (
        <div style={{
          position: 'absolute', bottom: 320, left: 56, right: 100,
          opacity: captionIn,
          transform: `translateY(${(1 - captionIn) * 25}px) scale(${ctaPulse})`,
        }}>
          <div style={{
            fontSize: isCTA ? 60 : 50, fontWeight: 900, color: 'white',
            textShadow: '0 2px 20px rgba(0,0,0,0.9), 0 4px 40px rgba(0,0,0,0.5)',
            lineHeight: 1.15, letterSpacing: -1,
            fontFamily: 'system-ui, -apple-system, sans-serif',
          }}>
            {scene.caption}
          </div>
          <div style={{
            fontSize: 26, color: 'rgba(255,255,255,0.65)', marginTop: 14,
            opacity: subIn,
            textShadow: '0 2px 10px rgba(0,0,0,0.9)',
            fontFamily: 'system-ui, -apple-system, sans-serif',
            fontWeight: 500,
          }}>
            {scene.sub}
          </div>
        </div>
      )}

      <div style={{ position: 'absolute', bottom: 260, left: 56, display: 'flex', gap: 6 }}>
        {scenes.map((_, i) => (
          <div key={i} style={{
            width: i === Math.max(0, sceneIdx) ? 22 : 7, height: 7, borderRadius: 4,
            background: i === Math.max(0, sceneIdx) ? 'white' : 'rgba(255,255,255,0.3)',
          }} />
        ))}
      </div>

      <div style={{
        position: 'absolute', top: 65, left: 50,
        display: 'flex', alignItems: 'center', gap: 10, opacity: 0.7,
      }}>
        <div style={{
          width: 36, height: 36, borderRadius: 10,
          background: 'linear-gradient(135deg, oklch(0.55 0.2 260), oklch(0.45 0.2 300))',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 15, fontWeight: 900, color: 'white',
        }}>IF</div>
        <div style={{ fontSize: 15, color: 'white', fontWeight: 600, fontFamily: 'system-ui' }}>Image Flow</div>
      </div>

      <div style={{ position: 'absolute', right: 20, bottom: 340, display: 'flex', flexDirection: 'column', gap: 22, alignItems: 'center', opacity: 0.35 }}>
        {[0, 1, 2, 3].map(i => (
          <div key={i} style={{ width: 42, height: 42, borderRadius: 21, background: 'rgba(255,255,255,0.12)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <div style={{ width: 18, height: 18, borderRadius: 9, background: 'rgba(255,255,255,0.45)' }} />
          </div>
        ))}
      </div>

      <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 3 }}>
        <div style={{ height: '100%', width: `${(frame / durationInFrames) * 100}%`, background: 'white', opacity: 0.5 }} />
      </div>

      {audio && <Audio src={audio} volume={0.9} />}
    </AbsoluteFill>
  );
}
